  const validChars = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ.@_-';
  for (let i = 0; i < email.length; i++) {
    if (validChars.indexOf(email[i]) === -1) {
